import React, { useEffect, useState } from "react";
import { PageShell } from "@/components/orderly/PageShell";
import { Info, Globe, Type, Palette, AtSign, Hash } from "lucide-react";
import { useTranslation } from "react-i18next";
import { storageKey } from "@/utils/storage";

interface SeoFormState {
  siteName: string;
  siteDescription: string;
  siteLanguage: string;
  siteLocale: string;
  twitterHandle: string;
  themeColor: string;
  keywords: string;
}

function useValidators(t: (key: string) => string) {
  return React.useMemo<
    Record<keyof SeoFormState, (value: string) => string | null>
  >(
    () => ({
      siteName: () => null,
      siteDescription: () => null,
      siteLanguage: value => {
        if (!value.trim()) return null;
        return /^[a-z]{2}(-[A-Z]{2})?$/.test(value)
          ? null
          : t("seoConfig.validation.languageFormat");
      },
      siteLocale: value => {
        if (!value.trim()) return null;
        return /^[a-z]{2}_[A-Z]{2}$/.test(value)
          ? null
          : t("seoConfig.validation.localeFormat");
      },
      twitterHandle: value => {
        if (!value.trim()) return null;
        return /^@[a-zA-Z0-9_]+$/.test(value)
          ? null
          : t("seoConfig.validation.twitterFormat");
      },
      themeColor: value => {
        if (!value.trim()) return null;
        return /^#[0-9A-Fa-f]{6}$/.test(value)
          ? null
          : t("seoConfig.validation.hexColor");
      },
      keywords: () => null,
    }),
    [t]
  );
}

export default function Page() {
  const { t } = useTranslation();
  const validators = useValidators(t);
  const [form, setForm] = useState<SeoFormState>({
    siteName: "",
    siteDescription: "",
    siteLanguage: "",
    siteLocale: "",
    twitterHandle: "",
    themeColor: "",
    keywords: "",
  });
  const [errors, setErrors] = useState<
    Partial<Record<keyof SeoFormState, string>>
  >({});
  const [toast, setToast] = useState<string | null>(null);

  useEffect(() => {
    setForm({
      siteName: localStorage.getItem(storageKey("orderlySeo.siteName")) || "",
      siteDescription:
        localStorage.getItem(storageKey("orderlySeo.siteDescription")) || "",
      siteLanguage:
        localStorage.getItem(storageKey("orderlySeo.siteLanguage")) || "",
      siteLocale:
        localStorage.getItem(storageKey("orderlySeo.siteLocale")) || "",
      twitterHandle:
        localStorage.getItem(storageKey("orderlySeo.twitterHandle")) || "",
      themeColor:
        localStorage.getItem(storageKey("orderlySeo.themeColor")) || "",
      keywords: localStorage.getItem(storageKey("orderlySeo.keywords")) || "",
    });
  }, []);

  function showToast(message: string) {
    setToast(message);
    setTimeout(() => setToast(null), 3000);
  }

  function updateField(field: keyof SeoFormState, value: string) {
    setForm(prev => ({ ...prev, [field]: value }));
    const error = validators[field](value);
    setErrors(prev => ({ ...prev, [field]: error || undefined }));
    if (typeof window !== "undefined") {
      localStorage.setItem(storageKey(`orderlySeo.${field}`), value);
    }
  }

  return (
    <PageShell pageTitle={t("seoConfig.title")}>
      <div className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-primary) p-6">
        <div className="mb-6 rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) p-4">
          <div className="flex items-start gap-3">
            <div className="flex h-8 w-8 shrink-0 items-center justify-center rounded-md bg-[rgba(188,135,255,0.12)] text-[#BC87FF]">
              <Info className="h-4 w-4" />
            </div>
            <div>
              <p className="text-sm font-medium text-(--fg-primary)">
                {t("seoConfig.title")}
              </p>
              <p className="text-sm text-(--fg-secondary)">
                {t("seoConfig.description")}
              </p>
              <ul className="mt-2 list-disc space-y-1 pl-4 text-xs text-(--fg-secondary)">
                <li>{t("seoConfig.info.siteName")}</li>
                <li>{t("seoConfig.info.description")}</li>
                <li>{t("seoConfig.info.twitterHandle")}</li>
                <li>{t("seoConfig.info.themeColor")}</li>
                <li>{t("seoConfig.info.keywords")}</li>
              </ul>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 gap-5 md:grid-cols-2">
          <div>
            <label className="mb-1.5 flex items-center gap-1.5 text-sm text-(--fg-secondary)">
              <Globe className="h-3.5 w-3.5" />
              {t("seoConfig.siteName")}
            </label>
            <input
              type="text"
              value={form.siteName}
              onChange={e => updateField("siteName", e.target.value)}
              placeholder={t("seoConfig.siteNamePlaceholder")}
              maxLength={100}
              className="w-full rounded-lg border border-(--line-subtle) bg-(--bg-input) px-3 py-2 text-sm text-(--fg-primary) outline-none transition-colors focus:border-(--line-brand)"
            />
            <p className="mt-1 text-xs text-(--fg-secondary)">
              {t("seoConfig.siteNameDescription")}
            </p>
          </div>

          <div>
            <label className="mb-1.5 flex items-center gap-1.5 text-sm text-(--fg-secondary)">
              <Type className="h-3.5 w-3.5" />
              {t("seoConfig.siteDescription")}
            </label>
            <input
              type="text"
              value={form.siteDescription}
              onChange={e => updateField("siteDescription", e.target.value)}
              placeholder={t("seoConfig.siteDescriptionPlaceholder")}
              maxLength={300}
              className="w-full rounded-lg border border-(--line-subtle) bg-(--bg-input) px-3 py-2 text-sm text-(--fg-primary) outline-none transition-colors focus:border-(--line-brand)"
            />
            <p className="mt-1 text-xs text-(--fg-secondary)">
              {t("seoConfig.siteDescriptionDescription")}
            </p>
          </div>

          <div>
            <label className="mb-1.5 flex items-center gap-1.5 text-sm text-(--fg-secondary)">
              <Globe className="h-3.5 w-3.5" />
              {t("seoConfig.siteLanguage")}
            </label>
            <input
              type="text"
              value={form.siteLanguage}
              onChange={e => updateField("siteLanguage", e.target.value)}
              placeholder={t("seoConfig.siteLanguagePlaceholder")}
              className="w-full rounded-lg border border-(--line-subtle) bg-(--bg-input) px-3 py-2 text-sm text-(--fg-primary) outline-none transition-colors focus:border-(--line-brand)"
            />
            {errors.siteLanguage ? (
              <p className="mt-1 text-xs text-[#FF6390]">
                {errors.siteLanguage}
              </p>
            ) : (
              <p className="mt-1 text-xs text-(--fg-secondary)">
                {t("seoConfig.siteLanguageDescription")}
              </p>
            )}
          </div>

          <div>
            <label className="mb-1.5 flex items-center gap-1.5 text-sm text-(--fg-secondary)">
              <Globe className="h-3.5 w-3.5" />
              {t("seoConfig.siteLocale")}
            </label>
            <input
              type="text"
              value={form.siteLocale}
              onChange={e => updateField("siteLocale", e.target.value)}
              placeholder={t("seoConfig.siteLocalePlaceholder")}
              className="w-full rounded-lg border border-(--line-subtle) bg-(--bg-input) px-3 py-2 text-sm text-(--fg-primary) outline-none transition-colors focus:border-(--line-brand)"
            />
            {errors.siteLocale ? (
              <p className="mt-1 text-xs text-[#FF6390]">{errors.siteLocale}</p>
            ) : (
              <p className="mt-1 text-xs text-(--fg-secondary)">
                {t("seoConfig.siteLocaleDescription")}
              </p>
            )}
          </div>

          <div>
            <label className="mb-1.5 flex items-center gap-1.5 text-sm text-(--fg-secondary)">
              <AtSign className="h-3.5 w-3.5" />
              {t("seoConfig.twitterHandle")}
            </label>
            <input
              type="text"
              value={form.twitterHandle}
              onChange={e => updateField("twitterHandle", e.target.value)}
              placeholder={t("seoConfig.twitterHandlePlaceholder")}
              className="w-full rounded-lg border border-(--line-subtle) bg-(--bg-input) px-3 py-2 text-sm text-(--fg-primary) outline-none transition-colors focus:border-(--line-brand)"
            />
            {errors.twitterHandle ? (
              <p className="mt-1 text-xs text-[#FF6390]">
                {errors.twitterHandle}
              </p>
            ) : (
              <p className="mt-1 text-xs text-(--fg-secondary)">
                {t("seoConfig.twitterHandleDescription")}
              </p>
            )}
          </div>

          <div>
            <label className="mb-1.5 flex items-center gap-1.5 text-sm text-(--fg-secondary)">
              <Palette className="h-3.5 w-3.5" />
              {t("seoConfig.themeColor")}
            </label>
            <div className="flex items-center gap-3">
              <input
                type="color"
                value={form.themeColor || "#1a1b23"}
                onChange={e => updateField("themeColor", e.target.value)}
                className="h-10 w-10 cursor-pointer rounded-md border-0 bg-transparent p-0"
              />
              <input
                type="text"
                value={form.themeColor}
                onChange={e => updateField("themeColor", e.target.value)}
                placeholder={t("seoConfig.themeColorPlaceholder")}
                className="w-full rounded-lg border border-(--line-subtle) bg-(--bg-input) px-3 py-2 text-sm text-(--fg-primary) outline-none transition-colors focus:border-(--line-brand)"
              />
              {form.themeColor && (
                <button
                  type="button"
                  onClick={() => updateField("themeColor", "")}
                  className="shrink-0 text-xs text-(--fg-secondary) transition-colors hover:text-(--fg-primary)"
                >
                  {t("seoConfig.clear")}
                </button>
              )}
            </div>
            {errors.themeColor ? (
              <p className="mt-1 text-xs text-[#FF6390]">{errors.themeColor}</p>
            ) : (
              <p className="mt-1 text-xs text-(--fg-secondary)">
                {t("seoConfig.themeColorDescription")}
              </p>
            )}
          </div>
        </div>

        <div className="mt-5">
          <label className="mb-1.5 flex items-center gap-1.5 text-sm text-(--fg-secondary)">
            <Hash className="h-3.5 w-3.5" />
            {t("seoConfig.keywords")}
          </label>
          <input
            type="text"
            value={form.keywords}
            onChange={e => updateField("keywords", e.target.value)}
            placeholder={t("seoConfig.keywordsPlaceholder")}
            maxLength={500}
            className="w-full rounded-lg border border-(--line-subtle) bg-(--bg-input) px-3 py-2 text-sm text-(--fg-primary) outline-none transition-colors focus:border-(--line-brand)"
          />
          <p className="mt-1 text-xs text-(--fg-secondary)">
            {t("seoConfig.keywordsDescription")}
          </p>
        </div>

        <div className="mt-6 flex items-center gap-3">
          <button
            type="button"
            onClick={() => showToast(t("seoConfig.configurationSaved"))}
            className="inline-flex items-center gap-2 rounded-full px-5 py-2.5 text-sm font-medium text-(--fg-primary) transition-opacity hover:opacity-90"
            style={{ background: "var(--bg-brand-grad)" }}
          >
            {t("seoConfig.saveConfiguration")}
          </button>
        </div>
      </div>

      {toast && (
        <div className="fixed bottom-5 left-1/2 z-100 -translate-x-1/2 rounded-full border border-(--line-brand) bg-(--bg-surface-primary) px-5 py-2.5 text-sm font-medium text-(--fg-primary) shadow-xl">
          {toast}
        </div>
      )}
    </PageShell>
  );
}
